def subset_sum(xs, target):
    # Handle negative target immediately
    if target < 0:
        return False
    # Use DP: dp[i] = True if sum i is achievable
    dp = [False] * (target + 1)
    dp[0] = True
    for x in xs:
        if x < 0:
            continue  # skip negative numbers as per problem statement
        # iterate backwards to avoid reusing the same element
        for s in range(target, x - 1, -1):
            if dp[s - x]:
                dp[s] = True
    return dp[target]
